19	const MAIN_ITEM_BASE: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const COMPONENT_BASE = 25;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE = 60;
30	
31	const PROCESSING_FEE = 5;
32	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
33	
34	const componentGroupBase = (count: number): number => {
35	  if (count === BLOCK_SIZE) return BLOCK_BASE;
36	  return count * COMPONENT_BASE;
37	};
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
40	
41	const sumMainItems = (items: Item[]): number =>
42	  items
43	    .filter((item) => !isComponent(item))
44	    .reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
45	
46	const countByType = (items: Item[]): Record<string, number> => {
47	  const counts: Record<string, number> = {};
48	  for (const item of items) {
49	    counts[item.type] = (counts[item.type] ?? 0) + 1;
50	  }
51	  return counts;
52	};
53	
54	const sumComponentGroups = (items: Item[]): number => {
55	  const counts = countByType(items.filter(isComponent));
56	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
57	};
58	
59	const policyBasePremium = (items: Item[]): number =>
60	  sumMainItems(items) + sumComponentGroups(items);
61	
62	const quotePremium = (step: QuoteStep): number => {
63	  const base = policyBasePremium(step.items);
64	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
65	  return Math.ceil(withFirstInsurance) + PROCESSING_FEE;
66	};
67	
68	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
69	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
70	  return { results };
71	};
